import json
import urllib.parse
import requests
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry
import boto3
from botocore.config import Config

def lambda_handler(event, context):
    # Get the request from the event
    request = event['Records'][0]['cf']['request']
    
    # Initialize secure session with retries
    session = requests.Session()
    retry_strategy = Retry(
        total=3,
        backoff_factor=1,
        status_forcelist=[429, 500, 502, 503, 504],
    )
    adapter = HTTPAdapter(max_retries=retry_strategy)
    session.mount("http://", adapter)
    session.mount("https://", adapter)
    
    # Get headers
    headers = request['headers']
    
    # Process X-Enrich-URL header
    if 'x-enrich-url' in headers:
        enrich_urls = headers['x-enrich-url']
        enrichment_data = {}
        
        for url_header in enrich_urls:
            url = url_header['value']
            try:
                # Validate URL
                parsed_url = urllib.parse.urlparse(url)
                if not all([parsed_url.scheme, parsed_url.netloc]):
                    continue
                    
                # Make secure request
                response = session.get(
                    url,
                    timeout=5,
                    headers={'User-Agent': 'Edge-Enrich-Service/1.0'},
                    verify=True
                )
                
                if response.status_code == 200:
                    try:
                        enrichment_data[parsed_url.netloc] = response.json()
                    except:
                        enrichment_data[parsed_url.netloc] = response.text
                else:
                    enrichment_data[parsed_url.netloc] = f"Error: {response.status_code}"
                    
            except Exception as e:
                enrichment_data[parsed_url.netloc] = f"Error: {str(e)}"
        
        # Add enrichment data to request headers
        if enrichment_data:
            headers['x-enrich-data'] = [{
                'key': 'X-Enrich-Data',
                'value': json.dumps(enrichment_data)
            }]
    
    # Return modified request
    return request